const safeParse = (val, min, max, defaultValue) => { const num = parseFloat(val); if (isNaN(num)) return defaultValue; return Math.max(min, Math.min(max, num)); };

const mhp = safeParse(inputs.mentalHealthProfessionalsPer100k, 0, 1000, 0);
const access = safeParse(inputs.accessToTherapyFacilities, 0, 100, 0);
const unemployment = safeParse(inputs.unemploymentRate, 0, 100, 0);
const poverty = safeParse(inputs.povertyRate, 0, 100, 0);
const safety = safeParse(inputs.perceivedSafetyScore, 1, 10, 1);
const cohesion = safeParse(inputs.socialCohesionScore, 1, 10, 1);
const programs = safeParse(inputs.communitySupportPrograms, 0, 100, 0);
const chronic = safeParse(inputs.chronicDiseasePrevalence, 0, 100, 0);

// 1. Normalize individual inputs to 0-100 scores

// Service Access
const mhpScore = Math.min(mhp / 1, 100); // 1 MHP per 100k gives 1 point. Capped at 100 for 100 MHPs per 100k.
const accessScore = access; // Directly use percentage as score

// Socio-Economic
const unemploymentScore = Math.max(0, 100 - unemployment); // Lower unemployment = higher score
const povertyScore = Math.max(0, 100 - poverty); // Lower poverty = higher score

// Safety & Cohesion
const safetyScore = (safety - 1) / 9 * 100; // Scale 1-10 to 0-100
const cohesionScore = (cohesion - 1) / 9 * 100; // Scale 1-10 to 0-100
const programsScore = Math.min(programs * 4, 100); // 25 programs = 100 points, capped

// Chronic Disease - Deduction factor
const chronicDeduction = chronic * 0.5; // Up to 50 points deduction for 100% prevalence

// 2. Aggregate individual scores into category scores
const serviceAccessScore = (mhpScore * 0.5 + accessScore * 0.5);
const socioEconomicScore = (unemploymentScore * 0.5 + povertyScore * 0.5);
const safetyCohesionScore = (safetyScore * 0.35 + cohesionScore * 0.35 + programsScore * 0.30);

// 3. Combine category scores with overall weights and apply deduction
let overallIndex = (
  serviceAccessScore * 0.40 +
  socioEconomicScore * 0.30 +
  safetyCohesionScore * 0.30
) - chronicDeduction;

// 4. Ensure the overall index is within 0-100 range
overallIndex = Math.max(0, Math.min(100, overallIndex));

return {
  overallIndex: overallIndex,
  serviceAccessScore: serviceAccessScore,
  socioEconomicScore: socioEconomicScore,
  safetyCohesionScore: safetyCohesionScore
};
